import{c as t,S as h,j as i,m as o}from"./chunks/framework.8aa1YH_s.js";const e=JSON.parse('{"title":"Danh mục câu hỏi (Ngân hàng câu hỏi)","description":"","frontmatter":{},"headers":[],"relativePath":"admin/danh-muc-cau-hoi.md","filePath":"admin/danh-muc-cau-hoi.md","lastUpdated":0}'),a={name:"admin/danh-muc-cau-hoi.md"};function c(r,n,g,l,u,d){return h(),i("div",null,[...n[0]||(n[0]=[o('<h1 id="danh-muc-cau-hoi-ngan-hang-cau-hoi" tabindex="-1">Danh mục câu hỏi (Ngân hàng câu hỏi) <a class="header-anchor" href="#danh-muc-cau-hoi-ngan-hang-cau-hoi" aria-label="Permalink to “Danh mục câu hỏi (Ngân hàng câu hỏi)”">​</a></h1><p><strong>Đường dẫn:</strong> <code>https://lamsonedutech.vn/admin/question/question</code></p><p>Danh mục câu hỏi là <strong>ngân hàng câu hỏi trung tâm</strong> của hệ thống. Mọi đề thi (đề ôn, đề mẫu, đánh giá đầu vào, đề kiểm tra) đều <strong>lấy câu từ đây</strong>. Việc xây dựng và làm giàu ngân hàng câu là công việc nền tảng quan trọng nhất của module Câu hỏi.</p><h2 id="vai-tro" tabindex="-1">Vai trò <a class="header-anchor" href="#vai-tro" aria-label="Permalink to “Vai trò”">​</a></h2><ul><li><strong>Nguồn</strong> cho <a href="./tieu-chi-de-thi">Tiêu chí đề thi</a> khi dựng đề random.</li><li><strong>Nguồn</strong> cho <a href="./de-on-khoa-hoc">Đề ôn khóa học</a>, <a href="./de-mau-luyen-thi">Đề mẫu Luyện thi</a>, <a href="./danh-gia-dau-vao">Đánh giá đầu vào</a> khi chọn câu cố định.</li><li><strong>Phân loại</strong> theo môn / chương / chuyên đề / mức độ / dạng câu để tìm và dùng lại dễ.</li></ul><h2 id="danh-sach-cau-hoi" tabindex="-1">Danh sách câu hỏi <a class="header-anchor" href="#danh-sach-cau-hoi" aria-label="Permalink to “Danh sách câu hỏi”">​</a></h2><p>Cột chính:</p><table tabindex="0"><thead><tr><th>Cột</th><th>Ý nghĩa</th></tr></thead><tbody><tr><td>ID</td><td>Mã câu hỏi (tự sinh)</td></tr><tr><td>Nội dung</td><td>Trích đầu của câu (50-100 ký tự)</td></tr><tr><td>Môn</td><td>Toán / Văn / Lý / Hóa / Sinh / Anh…</td></tr><tr><td>Chương / Chuyên đề</td><td></td></tr><tr><td>Mức độ</td><td>Nhận biết / Thông hiểu / Vận dụng / Vận dụng cao</td></tr><tr><td>Dạng câu</td><td>(xem dưới)</td></tr><tr><td>Trích đoạn</td><td>Có / Không liên kết <a href="./trich-doan-de-thi">Trích đoạn</a></td></tr><tr><td>Người tạo</td><td></td></tr><tr><td>Ngày tạo</td><td></td></tr><tr><td>Số lần dùng</td><td>Đã dùng trong bao nhiêu đề</td></tr><tr><td>Trạng thái</td><td>Đang dùng / Ngưng</td></tr></tbody></table><h3 id="bo-loc" tabindex="-1">Bộ lọc <a class="header-anchor" href="#bo-loc" aria-label="Permalink to “Bộ lọc”">​</a></h3><ul><li>Theo <strong>Môn</strong>, <strong>Chương / Chuyên đề</strong>.</li><li>Theo <strong>Mức độ</strong> (Nhận biết / Thông hiểu / Vận dụng / Vận dụng cao).</li><li>Theo <strong>Dạng câu</strong>.</li><li>Theo <strong>Kỳ thi áp dụng</strong> (ĐGNL / ĐGTD / TNTHPT / Chung).</li><li>Theo <strong>Người tạo</strong>, <strong>Ngày tạo</strong>.</li><li>Tìm kiếm full-text trong nội dung câu hỏi.</li></ul><h2 id="cac-dang-cau-hoi-ho-tro" tabindex="-1">Các dạng câu hỏi hỗ trợ <a class="header-anchor" href="#cac-dang-cau-hoi-ho-tro" aria-label="Permalink to “Các dạng câu hỏi hỗ trợ”">​</a></h2><table tabindex="0"><thead><tr><th>Dạng</th><th>Mô tả</th><th>Áp dụng</th></tr></thead><tbody><tr><td><strong>Trắc nghiệm 1 đáp án (4 lựa chọn)</strong></td><td>Học viên chọn 1 trong 4 (A/B/C/D)</td><td>Phổ biến nhất, dùng cho HSA, TNTHPT</td></tr><tr><td><strong>Trắc nghiệm nhiều đáp án</strong></td><td>Chọn nhiều lựa chọn đúng</td><td>TSA, đề ôn nâng cao</td></tr><tr><td><strong>Đúng - Sai nhiều ý</strong></td><td>1 câu gồm 4 ý nhỏ a/b/c/d, mỗi ý chọn Đúng/Sai</td><td>TNTHPT 2025+, TSA</td></tr><tr><td><strong>Trả lời ngắn / Điền số</strong></td><td>Học viên gõ đáp án dạng số hoặc chuỗi ngắn</td><td>HSA Tư duy định lượng, TNTHPT</td></tr><tr><td><strong>Điền vào chỗ trống</strong></td><td>Nhiều ô điền trong một câu</td><td>Ngữ pháp tiếng Anh, Văn</td></tr><tr><td><strong>Ghép cặp</strong></td><td>Nối cột A với cột B</td><td>Lịch sử, Địa, từ vựng</td></tr><tr><td><strong>Tự luận</strong></td><td>Học viên viết câu trả lời dài</td><td>Văn, Sử (THPT) - chấm thủ công</td></tr></tbody></table><h2 id="tao-moi-cau-hoi" tabindex="-1">Tạo mới câu hỏi <a class="header-anchor" href="#tao-moi-cau-hoi" aria-label="Permalink to “Tạo mới câu hỏi”">​</a></h2><ol><li><p>Bấm <strong>Thêm mới</strong>.</p></li><li><p>Khai báo <strong>phân loại</strong>:</p><ul><li><strong>Môn</strong>.</li><li><strong>Chương / Chuyên đề</strong> (dựa trên <a href="./khung-chuong-trinh">Khung chương trình</a>).</li><li><strong>Mức độ</strong>.</li><li><strong>Kỳ thi áp dụng</strong>: tick chọn ĐGNL / ĐGTD / TNTHPT / Chung.</li><li><strong>Dạng câu</strong>.</li></ul></li><li><p>Nhập <strong>Nội dung câu hỏi</strong> trong trình soạn thảo:</p><ul><li>Văn bản, định dạng, bảng, ảnh.</li><li>Công thức toán <strong>LaTeX</strong> (Toán/Lý/Hóa).</li><li>(Tùy chọn) liên kết <a href="./trich-doan-de-thi">Trích đoạn</a> — chọn từ dropdown.</li></ul></li><li><p>Nhập <strong>Đáp án</strong> theo dạng câu đã chọn:</p><h3 id="trac-nghiem-1-đap-an" tabindex="-1">Trắc nghiệm 1 đáp án <a class="header-anchor" href="#trac-nghiem-1-đap-an" aria-label="Permalink to “Trắc nghiệm 1 đáp án”">​</a></h3><ul><li>4 ô lựa chọn A, B, C, D.</li><li>Tick <strong>1 đáp án đúng</strong>.</li></ul><h3 id="trac-nghiem-nhieu-đap-an" tabindex="-1">Trắc nghiệm nhiều đáp án <a class="header-anchor" href="#trac-nghiem-nhieu-đap-an" aria-label="Permalink to “Trắc nghiệm nhiều đáp án”">​</a></h3><ul><li>Số lựa chọn (mặc định 4, có thể tăng).</li><li>Tick <strong>nhiều đáp án đúng</strong>.</li></ul><h3 id="đung-sai-nhieu-y" tabindex="-1">Đúng - Sai nhiều ý <a class="header-anchor" href="#đung-sai-nhieu-y" aria-label="Permalink to “Đúng - Sai nhiều ý”">​</a></h3><ul><li>Nhập 4 ý a, b, c, d.</li><li>Mỗi ý chọn <strong>Đúng</strong> hay <strong>Sai</strong>.</li></ul><h3 id="tra-loi-ngan-đien-so" tabindex="-1">Trả lời ngắn / Điền số <a class="header-anchor" href="#tra-loi-ngan-đien-so" aria-label="Permalink to “Trả lời ngắn / Điền số”">​</a></h3><ul><li>Nhập <strong>đáp án chuẩn</strong> (vd &quot;12.5&quot; hoặc &quot;x = 3&quot;).</li><li>(Tùy chọn) thêm <strong>đáp án chấp nhận</strong> (vd cho phép &quot;12.5&quot;, &quot;12,5&quot;, &quot;25/2&quot;).</li><li>Cấu hình <strong>so khớp</strong>: chính xác / không phân biệt hoa thường / khoảng dao động số.</li></ul><h3 id="đien-vao-cho-trong" tabindex="-1">Điền vào chỗ trống <a class="header-anchor" href="#đien-vao-cho-trong" aria-label="Permalink to “Điền vào chỗ trống”">​</a></h3><ul><li>Trong nội dung, dùng cú pháp <code>___</code> (3 dấu gạch dưới) để đánh dấu ô trống.</li><li>Liệt kê đáp án theo thứ tự ô.</li></ul><h3 id="ghep-cap" tabindex="-1">Ghép cặp <a class="header-anchor" href="#ghep-cap" aria-label="Permalink to “Ghép cặp”">​</a></h3><ul><li>Cột A (n mục) và Cột B (n mục).</li><li>Khai báo cặp đúng.</li></ul><h3 id="tu-luan" tabindex="-1">Tự luận <a class="header-anchor" href="#tu-luan" aria-label="Permalink to “Tự luận”">​</a></h3><ul><li>Gợi ý đáp án / barem điểm.</li><li>Bài làm sẽ được chấm thủ công sau khi học viên nộp.</li></ul></li><li><p>Nhập <strong>Lời giải / Giải thích đáp án</strong> (hiển thị cho học viên nếu được phép xem).</p></li><li><p>(Tùy chọn) <strong>Thẻ / Tag</strong>: gắn tag để tìm nhanh sau này (vd &quot;dễ&quot;, &quot;đề mẫu 2023&quot;, &quot;trắc nghiệm khó&quot;).</p></li><li><p>Bấm <strong>Lưu</strong>.</p></li></ol><h2 id="sua-cau-hoi" tabindex="-1">Sửa câu hỏi <a class="header-anchor" href="#sua-cau-hoi" aria-label="Permalink to “Sửa câu hỏi”">​</a></h2><ol><li>Tại danh sách, bấm <strong>Sửa</strong>.</li><li>Cập nhật nội dung, đáp án, phân loại.</li><li>Bấm <strong>Lưu</strong>.</li></ol><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Sửa câu hỏi đã <strong>dùng trong đề có lượt làm</strong> sẽ tạo ra <strong>không nhất quán</strong> giữa bài làm cũ và đáp án mới. Khuyến nghị:</p><ul><li>Nếu sửa lỗi chính tả nhẹ → OK.</li><li>Nếu thay đổi nội dung / đáp án → tạo <strong>câu mới</strong>, không sửa câu cũ. Câu cũ chuyển sang trạng thái <strong>Ngưng</strong>.</li></ul></div><h2 id="xoa-cau-hoi" tabindex="-1">Xóa câu hỏi <a class="header-anchor" href="#xoa-cau-hoi" aria-label="Permalink to “Xóa câu hỏi”">​</a></h2><ol><li>Tại danh sách, bấm <strong>Xóa</strong>.</li><li>Xác nhận.</li></ol><div class="danger custom-block"><p class="custom-block-title custom-block-title-default">DANGER</p><p>Câu hỏi <strong>đang dùng trong đề thi</strong> không xóa được trực tiếp. Bạn cần:</p><ul><li>Gỡ câu khỏi tất cả đề đang dùng, <strong>hoặc</strong></li><li>Đặt trạng thái câu về <strong>Ngưng</strong> — câu sẽ không xuất hiện trong các đề mới dựng từ tiêu chí, nhưng vẫn giữ trong đề cũ.</li></ul></div><h2 id="nhap-excel-hang-loat" tabindex="-1">Nhập Excel hàng loạt <a class="header-anchor" href="#nhap-excel-hang-loat" aria-label="Permalink to “Nhập Excel hàng loạt”">​</a></h2><p>Đây là cách hiệu quả nhất để xây ngân hàng câu hỏi.</p><ol><li><p>Bấm <strong>Nhập Excel</strong> → tải xuống <strong>Mẫu Excel</strong> (Template).</p></li><li><p>Mẫu Excel có các cột chuẩn:</p><table tabindex="0"><thead><tr><th>Cột</th><th>Mô tả</th></tr></thead><tbody><tr><td>Môn</td><td>Toán / Văn / Lý… (đúng tên trong hệ thống)</td></tr><tr><td>Chuyên đề</td><td>Đúng tên chuyên đề thuộc <a href="./khung-chuong-trinh">Khung chương trình</a></td></tr><tr><td>Mức độ</td><td>Nhận biết / Thông hiểu / Vận dụng / Vận dụng cao</td></tr><tr><td>Dạng</td><td>Trắc nghiệm 1 đáp án / Nhiều đáp án / Đúng-Sai / Trả lời ngắn / Điền vào chỗ trống / Ghép cặp / Tự luận</td></tr><tr><td>Kỳ thi</td><td>ĐGNL / ĐGTD / TNTHPT / Chung (nhiều giá trị ngăn bằng dấu <code>,</code>)</td></tr><tr><td>Nội dung</td><td>Nội dung câu hỏi (có thể chứa LaTeX: <code>$x^2$</code>)</td></tr><tr><td>Đáp án A, B, C, D</td><td>Cho dạng trắc nghiệm</td></tr><tr><td>Đáp án đúng</td><td>A / B / C / D (hoặc nhiều, vd &quot;A,C&quot;)</td></tr><tr><td>Lời giải</td><td>(tùy chọn)</td></tr><tr><td>Tag</td><td>(tùy chọn)</td></tr></tbody></table></li><li><p>Điền dữ liệu vào mẫu.</p></li><li><p>Bấm <strong>Tải file lên</strong>.</p></li><li><p>Hệ thống xem trước: hiển thị số dòng hợp lệ, số dòng lỗi (kèm lý do).</p></li><li><p>Bấm <strong>Nhập</strong> để xác nhận.</p></li></ol><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Mẹo nhập nhanh:</p><ul><li>Copy từ file Word có công thức? Hãy convert công thức sang <strong>LaTeX</strong> trước (dùng plugin MathType → LaTeX).</li><li>Câu có ảnh? Tải ảnh trước qua trang nội bộ, lấy URL, dán vào ô nội dung dạng <code>&lt;img src=&quot;URL&quot;/&gt;</code>. Hoặc nhập câu trước rồi vào sửa từng câu để chèn ảnh.</li><li>Nhập theo từng môn / chuyên đề → dễ kiểm soát hơn là nhập 1 file 5000 câu.</li></ul></div><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Mỗi lần nhập tối đa <strong>2000 câu/lần</strong> để tránh quá tải. Chia file nếu cần thiết.</p></div><h2 id="xuat-excel" tabindex="-1">Xuất Excel <a class="header-anchor" href="#xuat-excel" aria-label="Permalink to “Xuất Excel”">​</a></h2><ul><li><strong>Xuất Excel danh sách câu hỏi</strong>: tải toàn bộ hoặc theo bộ lọc.</li><li>File xuất ra <strong>đúng format</strong> của mẫu nhập → có thể chỉnh sửa và import lại (sao lưu).</li></ul><h2 id="sao-chep-cau-hoi" tabindex="-1">Sao chép câu hỏi <a class="header-anchor" href="#sao-chep-cau-hoi" aria-label="Permalink to “Sao chép câu hỏi”">​</a></h2><p>Khi cần tạo câu tương tự (chỉ đổi số/dữ liệu):</p><ol><li>Tại dòng câu, bấm <strong>Nhân bản</strong>.</li><li>Mở câu copy, sửa nội dung và đáp án.</li><li>Lưu.</li></ol><h2 id="gan-trich-đoan" tabindex="-1">Gắn trích đoạn <a class="header-anchor" href="#gan-trich-đoan" aria-label="Permalink to “Gắn trích đoạn”">​</a></h2><p>Đối với các câu <strong>đọc hiểu</strong> (có chung 1 đoạn văn):</p><ol><li>Tạo trước <a href="./trich-doan-de-thi">Trích đoạn</a>.</li><li>Trong câu hỏi, chọn trích đoạn ở dropdown <strong>Trích đoạn</strong>.</li><li>Khi học viên làm bài, đoạn văn và câu hỏi hiển thị bên cạnh nhau.</li></ol><h2 id="bao-loi-cau-hoi" tabindex="-1">Báo lỗi câu hỏi <a class="header-anchor" href="#bao-loi-cau-hoi" aria-label="Permalink to “Báo lỗi câu hỏi”">​</a></h2><p>Học viên/giáo viên có thể <strong>báo lỗi</strong> một câu (nội dung sai, đáp án không đúng, format hỏng):</p><ol><li>Vào tab <strong>Báo lỗi</strong> trong trang danh mục câu.</li><li>Xem danh sách báo cáo + nội dung mô tả.</li><li>Mở câu, sửa hoặc đánh dấu <strong>Đã xử lý</strong>.</li></ol><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Cấu hình ai được báo lỗi (Học viên / Giáo viên / Cả hai) ở <a href="./phan-quyen">Phân quyền</a>.</p></div><h2 id="thong-ke-cau-hoi" tabindex="-1">Thống kê câu hỏi <a class="header-anchor" href="#thong-ke-cau-hoi" aria-label="Permalink to “Thống kê câu hỏi”">​</a></h2><p>Trong trang chi tiết câu, xem:</p><ul><li><strong>Số lần xuất hiện</strong> trong các đề.</li><li><strong>Tỷ lệ học viên trả lời đúng</strong> (độ khó thực tế).</li><li><strong>Lựa chọn nào học viên chọn nhiều nhất</strong> (phân tích đáp án nhiễu).</li></ul><p>→ Dùng để <strong>cân chỉnh</strong> mức độ câu hỏi: nếu mức &quot;Nhận biết&quot; mà chỉ 30% trả lời đúng → có thể câu khó hơn dự kiến → đổi sang &quot;Thông hiểu&quot;.</p><h2 id="cau-hoi-thuong-gap" tabindex="-1">Câu hỏi thường gặp <a class="header-anchor" href="#cau-hoi-thuong-gap" aria-label="Permalink to “Câu hỏi thường gặp”">​</a></h2><p><strong>Tôi nhập Excel báo lỗi &quot;Chuyên đề không tồn tại&quot; - sao?</strong> → Tên chuyên đề trong Excel phải <strong>trùng chính xác</strong> với chuyên đề đã tạo trong <a href="./khung-chuong-trinh">Khung chương trình</a>. Kiểm tra dấu, chữ thường-hoa.</p><p><strong>Một câu có thể thuộc nhiều môn / nhiều chuyên đề không?</strong> → Mỗi câu thuộc <strong>1 môn + 1 chuyên đề chính</strong>, nhưng có thể gắn nhiều <strong>tag</strong> để tham chiếu chéo (vd câu Hóa hữu cơ tag thêm &quot;Tổng hợp&quot;).</p><p><strong>Công thức toán bị vỡ khi nhập Excel?</strong> → Excel không hỗ trợ LaTeX trực tiếp. Hãy gõ LaTeX dạng <code>$x^2 + 2x - 1 = 0$</code> trong ô nội dung. Hệ thống tự render khi hiển thị cho học viên.</p><p><strong>Tôi đã có ngân hàng câu hỏi cũ trên file Word - làm sao chuyển?</strong> → Copy từng câu vào Excel mẫu, hoặc dùng dịch vụ chuyển đổi (liên hệ quản trị). Không có cách import trực tiếp từ Word do format quá đa dạng.</p><p><strong>Câu hỏi cũ ai cũng đoán đúng - tôi muốn ngưng dùng?</strong> → Đặt câu về <strong>Ngưng</strong>. Câu sẽ không xuất hiện trong tiêu chí random nữa, nhưng vẫn nằm trong các đề đã chốt câu cố định.</p><p><strong>Có giới hạn số câu trong ngân hàng?</strong> → Không có giới hạn cứng. Hệ thống đã được thử nghiệm với trên 100.000 câu. Khuyến nghị nên phân loại tốt để dễ tìm.</p><p><strong>Học viên báo &quot;câu này đáp án sai&quot; - tôi xử lý sao?</strong> → Vào tab <strong>Báo lỗi</strong>, kiểm tra. Nếu đúng là sai → sửa câu hoặc tạo câu mới + ngưng câu cũ. Nếu báo nhầm → đánh dấu <strong>Đã xử lý + Không đổi</strong>.</p><p><strong>Tôi không muốn giáo viên thấy lời giải - chỉ admin xem được.</strong> → Cấu hình ở <a href="./phan-quyen">Phân quyền</a>: phân quyền &quot;Xem lời giải câu hỏi&quot; chỉ cho vai trò Admin.</p>',50)])])}const p=t(a,[["render",c]]);export{e as __pageData,p as default};
